            ` ${size * -0.304} ${size * -1.4022} ${size * -0.304} ${size * -1.425}C` +
            ` ${size * -0.304} ${size * -1.5732} ${size * -0.1862} ${size * -1.691} ${size * -0.038} ${size * -1.691}C` +
            ` ${size * -0.0152} ${size * -1.691} ${0} ${size * -1.7062} ${0} ${size * -1.729}S` +
            ` ${size * -0.0152} ${size * -1.767} ${size * -0.038} ${size * -1.767}z`
